mapper.select:
select desb.borehole_length ,bkab.*,r.roadway,z.zone_name,bc.borehole_category,pb.purpose_borehole,s.shift_info,np.navigation_point_name, s.shift_info AS groutingShift,TIMESTAMPDIFF(HOUR,time_end_flushing,time_begin_flushing) as totalTimeFlushing from t_bk_act_borehole_info bkab LEFT JOIN t_roadway r ON bkab.roadway_id=r.id LEFT JOIN t_roadway_zone z ON bkab.roadway_zone_id=z.id LEFT JOIN t_borehole_category bc ON bkab.category_code=bc.category_code LEFT JOIN t_purpose_borehole pb ON bkab.purpose_borehole_id=pb.id LEFT JOIN t_shiftinfo s ON bkab.shift_id=s.id LEFT JOIN t_navigation_point np ON bkab.navigation_point_id=np.id LEFT JOIN t_designed_borehole desb ON bkab.roadway_id=desb.roadway_id AND bkab.group_no=desb.group_no AND bkab.borehole_no=desb.borehole_no where 1=1 AND bkab.roadway_id IN
#{item}
AND bkab.group_no = #{groupNo}
AND bkab.drilling_location IN
#{item}
and bkab.borehole_no IN
#{item}
and bkab.actual_coal_amount_flushed between #{actualcoalamountflushed1} and #{actualcoalamountflushed2}
and bkab.terminal_hole_date between #{terminalholedate1} and #{terminalholedate2}

SELECT a.id,r.roadway,a.drilling_location,a.borehole_code,d.angle as desAngle,a.angle as actAngle,d.inclination_angle as desInclinationAngle, a.inclination_angle as actInclinationAngle,d.borehole_length as desBoreholeLength,a.borehole_length as actBoreholeLength,CONCAT('岩1:',a.depth_1st_rock_seam_start,'-', a.depth_1st_rock_seam_end,',煤1:',a.depth_1st_coal_seam_start,'-',a.depth_1st_coal_seam_end,',岩2:',a.depth_2st_rock_seam_start, '-',a.depth_2st_rock_seam_end,',煤2:',a.depth_2st_coal_seam_start,'-',a.depth_2st_coal_seam_end,',岩3:',a.depth_3st_rock_seam_start, '-',a.depth_3st_rock_seam_end) as seerockcoalcase,a.sealing_material,ROUND(a.punching_paragraph2-a.punching_paragraph1,2)as flushingLength,a.actual_coal_amount_flushed from t_bk_act_borehole_info a LEFT JOIN t_designed_borehole d ON CONCAT(a.roadway_id,a.group_no,a.borehole_no) =CONCAT(d.roadway_id,d.group_no,d.borehole_no) LEFT JOIN t_navigation_point n ON a.navigation_point_id =n.id LEFT JOIN t_sealing_grouting s ON a.id=s.Borehole_id LEFT JOIN t_roadway r ON r.Id = a.roadway_id LEFT JOIN t_purpose_borehole p ON p.Id = a.purpose_borehole_id where 1=1 AND a.roadway_id=#{roadwayId} AND a.group_no IN
#{item}
AND a.purpose_borehole_Id IN
#{item}
AND a.borehole_no IN
#{item}
AND a.checking_date BETWEEN #{startDate} AND #{endDate}

select id
from t_bk_act_borehole_info
where roadway_id = #{roadwayId}
  and group_no = #{groupNo}
  and borehole_no = #{boreholeNO}

select id
from t_bk_act_borehole_info
where group_no = #{groupNo}
  and borehole_no = #{boreholeNO}
  and roadway_id = (SELECT id from t_roadway where roadway = #{roadway})

select id
from t_bk_act_borehole_info
where roadway_zone_id = #{roadwayZoneId}
